def transition(state, action):
    s = dict(state)
    name = action["name"]
    if s.get("stopped"):
        return s                              # halted: every action is a no-op
    if name == "call":
        cost = s["call_cost"]
        if s["budget"] >= cost:
            s["budget"] -= cost
            s["spent"] += cost
            s["calls"] += 1
            s["cached"] += 1                  # result is now reusable from cache
            s["results"] += 1
    elif name == "cache":
        cost = s["cache_cost"]
        if s["cached"] > 0 and s["budget"] >= cost:
            s["budget"] -= cost
            s["spent"] += cost
            s["cache_hits"] += 1              # served a result from the cache
            s["results"] += 1
    elif name == "stop":
        s["stopped"] = True
    return s

