def perceive(data):
    cfg = {"budget": 100, "call_cost": 10, "cache_cost": 1}
    for line in str(data).splitlines():
        if ':' not in line:
            continue
        key, val = line.split(':', 1)
        key = key.strip().lower().replace(' ', '_')
        val = val.strip()
        if key in cfg and val.lstrip('-').isdigit():
            cfg[key] = max(0, int(val))
    return {
        "budget": cfg["budget"],
        "call_cost": cfg["call_cost"],
        "cache_cost": cfg["cache_cost"],
        "spent": 0, "calls": 0, "cache_hits": 0,
        "cached": 0, "results": 0, "stopped": False,
    }
